import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';
import reportWebVitals from './reportWebVitals';
import mongoClient from './api/mongoFrontend';

// Configure mongoFrontend from environment variables (REACT_APP_...)
// Create a local .env file with REACT_APP_MONGO_API_URL and REACT_APP_MONGO_API_KEY
// e.g.
// REACT_APP_MONGO_API_URL=https://data.mongodb-api.com/app/<APP-ID>/endpoint/data/v1
// REACT_APP_MONGO_API_KEY=<your-data-api-key>
// REACT_APP_MONGO_DATA_SOURCE=Cluster0
// REACT_APP_MONGO_DATABASE=Finnalyze
mongoClient.setMongoConfig({
  apiUrl: process.env.REACT_APP_MONGO_API_URL || '',
  apiKey: process.env.REACT_APP_MONGO_API_KEY || '',
  dataSource: process.env.REACT_APP_MONGO_DATA_SOURCE || mongoClient.getConfig().dataSource,
  database: process.env.REACT_APP_MONGO_DATABASE || mongoClient.getConfig().database,
});

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
